#include <iostream>
#include <string>
using namespace std;

class Car
{
private:
    string brand;
    string model;
    int year;

public:
    // Constructor
    Car(string b, string m, int y)
    {
        brand = b;
        model = m;
        year = y;
    }

    void displayInfo()
    {
        cout << year << " " << brand << " " << model << endl;
    }

    int getAge(int currentYear)
    {
        return currentYear - year;
    }
};

int main()
{
    Car car1("Toyota", "Corolla", 2020);
    Car car2("Honda", "Civic", 2018);

    cout << "Araba bilgileri:" << endl;
    car1.displayInfo();
    car2.displayInfo();

    cout << "\nArac yaslari (2026'ya gore):" << endl;
    cout << "Car1 yasi: " << car1.getAge(2026) << " yil" << endl;
    cout << "Car2 yasi: " << car2.getAge(2026) << " yil" << endl;

    return 0;
}
